-- 設置隔離級別（會話級別）
SET SESSION TRANSACTION ISOLATION LEVEL READ COMMITTED;

-- 設置隔離級別（全局）
SET GLOBAL TRANSACTION ISOLATION LEVEL REPEATABLE READ;

-- 髒讀示例（READ UNCOMMITTED）
-- Session1: 開始事務，修改id=1的記錄但未提交
START TRANSACTION;
UPDATE users SET name='Tom' WHERE id=1;

-- Session2: 讀到未提交的修改（髒讀）
SET SESSION TRANSACTION ISOLATION LEVEL READ UNCOMMITTED;
SELECT * FROM users WHERE id=1;  -- 結果：Tom（髒數據）

-- Session1: 回滾
ROLLBACK;

-- Session2: 再次讀取
SELECT * FROM users WHERE id=1;  -- 結果：原始值

-- 不可重複讀示例（READ COMMITTED）
-- Session1: READ COMMITTED
START TRANSACTION;
SELECT * FROM users WHERE id=1;  -- 結果：Alice

-- Session2: 提交修改
UPDATE users SET name='Bob' WHERE id=1;
COMMIT;

-- Session1: 再次讀取（不可重複讀！）
SELECT * FROM users WHERE id=1;  -- 結果：Bob
COMMIT;

-- 1. 行鎖示例
