-- 查詢並加行鎖（排他鎖）
SELECT * FROM users WHERE id = 1 FOR UPDATE;

-- 更新（自動加排他鎖）
UPDATE users SET name = 'Tom' WHERE id = 1;

COMMIT;  -- 釋放鎖

-- 2. 共享鎖示例
START TRANSACTION;

-- 查詢加共享鎖
SELECT * FROM users WHERE id = 1 LOCK IN SHARE MODE;

COMMIT;

-- 3. 死鎖示例（避免！）
-- Session1:
START TRANSACTION;
UPDATE users SET name='A' WHERE id=1;  -- 鎖住id=1
UPDATE users SET name='B' WHERE id=2;  -- 嘗試鎖id=2

-- Session2:
START TRANSACTION;
UPDATE users SET name='C' WHERE id=2;  -- 鎖住id=2
UPDATE users SET name='D' WHERE id=1;  -- 嘗試鎖id=1 -> 死鎖！

