// 行鎖示例

// 1. 共享鎖 (Shared Lock)
START TRANSACTION;
SELECT * FROM users WHERE id = 1 LOCK IN SHARE MODE;
// 其他session可以讀，但唔可以修改
COMMIT;

// 2. 排他鎖 (Exclusive Lock)  
START TRANSACTION;
SELECT * FROM users WHERE id = 1 FOR UPDATE;
// 其他session既讀同寫都會阻塞
UPDATE users SET name = 'Tom' WHERE id = 1;
COMMIT;

// 3. 意向鎖 (自動加)
-- 當你咩都唔做既時候：
SELECT * FROM users;  // InnoDB 會加 IS lock
UPDATE users SET name = 'Tom'; // 會加 IX lock

// 意向鎖既作用：
// 通知其他session：我準備要呢張表既某啲row
// 咁其他session要加表級鎖既時候，就知道有衝突

// 查看鎖信息
SELECT * FROM information_schema.INNODB_LOCKS;
SELECT * FROM information_schema.INNODB_LOCK_WAITS;
SHOW ENGINE INNODB STATUS;

// Gap Lock 示例

// 假設 users 表既 age 索引有: 10, 20, 30, 40

// Session 1:
START TRANSACTION;
SELECT * FROM users WHERE age = 20 FOR UPDATE;
// 會加:
// 1. Record Lock: 鎖住 age=20 既記錄
// 2. Gap Lock: 鎖住 (10,20) 和 (20,30) 既間隙

// Session 2:
INSERT INTO users (age) VALUES (15);  // 會被阻塞！(15 in (10,20))
INSERT INTO users (age) VALUES (25);  // 會被阻塞！(25 in (20,30))

// 有效防止左「幻讀」！

// Next-Key Lock = Record Lock + Gap Lock
// 如果 age=20 存在:
// Next-Key Lock: 鎖住 [10, 20) 和 [20, 30)

// 查看 Gap Lock
SHOW ENGINE INNODB STATUS;
-- 會顯示 Lock mode: GAP

// 禁用 Gap Lock
SET tx_isolation = 'READ-COMMITTED';
-- 注意：呢個會降低隔離級別，可能出現幻讀

