# 正確既加鎖
SET lock:order:123456 nx ex 30
# 返回 OK 表示獲取鎖成功
# 返回 nil 表示獲取失敗

# 錯誤既釋放鎖（會釋放其他人既鎖！）
DEL lock:order:123456

# 正確既釋放鎖（Lua 腳本）
if redis.call("get", KEYS[1]) == ARGV[1] then
    return redis.call("del", KEYS[1])
else
    return 0
end

# Java Redisson 實現
RLock lock = redissonClient.getLock("lock:order:123456");
lock.lock(30, TimeUnit.SECONDS);  // 自動續期
try {
    // 業務邏輯
} finally {
    lock.unlock();
}

# Redisson 看門狗
// 默認 30 秒鎖，10 秒自動續期
// 業務執行緊就會自動延長

# 普通方式：10次網絡往返
for i in range(10):
    r.set(f"key{i}", f"value{i}")  # 每次都等server回覆

# Pipeline：1次網絡往返
pipe = redis.pipeline()
for i in range(10):
    pipe.set(f"key{i}", f"value{i}")
pipe.execute()  # 一次過發送，一次過回覆

# Python 示例
import redis
r = redis.Redis(host='localhost', port=6379)
pipe = r.pipeline()
pipe.set('foo', 'bar')
pipe.get('foo')
result = pipe.execute()  # [True, b'bar']

# Java 示例
List<Object> results = redisTemplate.executePipelined(new SessionCallback<Object>() {
    @Override
    public Object execute(RedisOperations operations) throws DataAccessException {
        for (int i = 0; i < 1000; i++) {
            operations.opsForValue().set("key" + i, "value" + i);
            operations.opsForValue().get("key" + i);
        }
        return null;
    }
});

