SqlSessionFactory factory = new SqlSessionFactoryBuilder().build(inputStream);
SqlSession session = factory.openSession();
UserMapper mapper = session.getMapper(UserMapper.class);

// #{} vs ${} 示例

// #{} - 安全，預編譯
@Select("SELECT * FROM users WHERE id = #{id}")
User findById(Long id);

// 實際執行既SQL:
// SELECT * FROM users WHERE id = ?
// 參數會被 PreparedStatement 處理

// ${} - 直接替換 (危險!)
@Select("SELECT * FROM ${tableName} WHERE status = #{status}")
List<User> findByTable(@Param("tableName") String table, 
                       @Param("status") int status);

// 危險既例子 - SQL 注入!
@Select("SELECT * FROM users WHERE name = '${name}'")
User findByName(String name);
// 如果 name = "Tom' OR '1'='1"
// 會變成: SELECT * FROM users WHERE name = 'Tom' OR '1'='1'

// 正確既 ORDER BY 用法
@Select("SELECT * FROM users ORDER BY #{column} ${order}")
List<User> findAll(@Param("column") String column,
                   @Param("order") String order);

// 調用
findAll("name", "ASC");
// SQL: SELECT * FROM users ORDER BY name ASC

// 最佳實踐
// 1. 永遠用 #{} 除了表名/ORDER BY
// 2. 表名用白名單驗證
// 3. 使用 @Param 命名參數

// 緩存生效
session.selectOne("findById", 1);
session.selectOne("findById", 1); // 第二次從緩存取

