// AQS 內部結構示意
public abstract class AbstractQueuedSynchronizer {
    // 雙向隊列頭尾
    private volatile Node head;
    private volatile Node tail;

    // 資源狀態
    private volatile int state;

    // 獲取鎖 - 子類實現既模板方法
    protected boolean tryAcquire(int arg) {
        throw new UnsupportedOperationException();
    }

    // 釋放鎖 - 子類實現既模板方法  
    protected boolean tryRelease(int arg) {
        throw new UnsupportedOperationException();
    }

    // 公共既acquire方法
    public final void acquire(int arg) {
        if (!tryAcquire(arg) && 
            acquireQueued(addWaiter(Node.EXCLUSIVE), arg))
            selfInterrupt();
    }
}

// ReentrantLock 內部既Sync類就係extends AQS
class Sync extends AbstractQueuedSynchronizer {
    protected boolean tryAcquire(int acquires) {
        // CAS 操作
        while (true) {
            int c = getState();
            int c0 = c - acquires;
            if (compareAndSetState(c, c0))
                return true;
        }
    }
}

// 傳統 CAS - 有 ABA 問題
AtomicInteger atomic = new AtomicInteger(100);
// Thread A: 讀取 100
// Thread B: 100 -> 101 -> 100 (ABA)
// Thread A: CAS(100, 200) 成功！但實際已經被修改過

// 使用版本號解決 ABA 問題
AtomicStampedReference<Integer> stampedRef = 
    new AtomicStampedReference<>(100, 1);

// Thread A 讀取
int stamp = stampedRef.getStamp();
Integer value = stampedRef.getReference();

// Thread B 修改
stampedRef.compareAndSet(value, 101, stamp, stamp + 1);
stampedRef.compareAndSet(101, 100, stamp + 1, stamp + 2);

// Thread A 再試
// stamp 已經變左，CAS 會失敗！
boolean success = stampedRef.compareAndSet(
    value, 200, stamp, stamp + 2  // 失敗，因為 stamp 唔匹配
);

// 使用場景：實現無鎖棧
public class LockFreeStack<T> {
    private AtomicStampedReference<Node<T>> top = 
        new AtomicStampedReference<>(null, 0);

    public void push(T item) {
        while (true) {
            Node<T> oldTop = top.getReference();
            int oldStamp = top.getStamp();
            Node<T> newNode = new Node<>(item, oldTop);
            if (top.compareAndSet(oldTop, newNode, oldStamp, oldStamp + 1)) {
                return;
            }
        }
    }
}

// Disruptor 核心概念
// 1. RingBuffer - 預分配既環形緩冲區
public class RingBuffer<E> {
    private final int bufferSize;
    private final E[] entries;

    // bufferSize 必須係 2 既 n 次方
    public RingBuffer(int bufferSize) {
        this.bufferSize = bufferSize;
        this.entries = (E[]) new Object[bufferSize];
    }

    // 高效既 index 計算
    public long index(long sequence) {
        return sequence & (bufferSize - 1);  // & 比 % 快
    }
}

// 2. 避免 False Sharing - 緩存行填充
public class PaddedLong {
    long p1, p2, p3, p4, p5, p6, p7, p8;  // 填充
    private volatile long value;
    long p9, p10, p11, p12, p13, p14, p15, p16;  // 填充
}

