// ThreadLocal 內存洩漏既示意圖
// ThreadLocalMap 結構:
// Thread -> threadLocals (強引用) -> ThreadLocalMap (強引用)
//   -> table[] -> Entry(key=弱引用ThreadLocal, value=強引用)

// 正常情況：
ThreadLocal<String> local = new ThreadLocal<>();
local.set("hello");
// local 變null可以被GC，但 value 仲被 Entry 引用

// 問題場景：線程池
ExecutorService pool = Executors.newFixedThreadPool(1);
pool.submit(() -> {
    ThreadLocal<byte[]> buffer = new ThreadLocal<>();
    buffer.set(new byte[1024 * 1024 * 10]);  // 10MB
    // 方法結束，但 ThreadLocal 對象出Scope
    // ThreadLocal 被GC，key變null
    // 但 value (10MB) 因為線程重用而不斷累積！
});

// 正確既使用方式：
public class UserContext {
    private static final ThreadLocal<User> contextHolder = 
        new ThreadLocal<>();

    public static void set(User user) {
        contextHolder.set(user);
    }

    public static User get() {
        return contextHolder.get();
    }

    // 必須調用！
    public static void clear() {
        contextHolder.remove();  // 防止內存洩漏
    }
}

// Spring @Async 既解決方案：
@Async
public void asyncMethod() {
    try {
        // 使用 ThreadLocal
    } finally {
        UserContext.clear();  // 一定要clean！
    }
}

// 偏向鎖 Mark Word 結構 (64位):
// [unused:1 bit][偏向鎖標志:1 bit][分代年齡:2 bits][對象頭類型:2 bits][hashcode:25 bits][thread:54 bits][epoch:2 bits]

// 偏向鎖獲取過程：
// 1. 訪問對象既Mark Word
// 2. 如果係未偏向狀態：用CAS將線程ID設置入Mark Word
// 3. 如果係已偏向狀態：檢查Mark Word既線程ID
//    - 如果相同：直接進入同步塊
//    - 如果不同：嘗試CAS偏向鎖升級為輕量級鎖

// 輕量級鎖獲取過程：
// 1. 在線程既Stack Frame創建Lock Record
// 2. 將對象頭既Mark Word拷貝到Lock Record既Displaced Mark Word
// 3. 用CAS將對象頭既Mark Word更新為指向Lock Record既指針
// 4. 如果成功：獲得輕量級鎖
// 5. 如果失敗：自旋重試（默認10次）

// JVM 啟動參數：
-XX:+UseBiasedLocking           // 啟用偏向鎖（默認）
-XX:BiasedLockingStartupDelay=0 // 禁用延遲
-XX:+UseHeavyMonitors            // 直接使用重量級鎖
-XX:PreBlockSpin=20              // 自旋次數

// 實際代碼觀察：
synchronized(obj) {
    // 第一次：偏向鎖
    // 有競爭：輕量級鎖
    // 競爭激烈：重量級鎖
}

// 查看類加載器層次
public class ClassLoaderDemo {
    public static void main(String[] args) {
        // Bootstrap ClassLoader - C++實現，輸出null
        System.out.println("Bootstrap: " + 
            String.class.getClassLoader());  // null

        // Extension ClassLoader
        System.out.println("Extension: " + 
            com.sun.crypto.provider.AESCrypto.class.getClassLoader());

        // Application ClassLoader
        System.out.println("Application: " + 
            ClassLoaderDemo.class.getClassLoader());

        // 查看層次關係
        ClassLoader loader = ClassLoaderDemo.class.getClassLoader();
        while (loader != null) {
            System.out.println(loader);
            loader = loader.getParent();
        }
    }
}

// 自定義類加載器示例
public class MyClassLoader extends ClassLoader {
    @Override
    protected Class<?> findClass(String name) throws ClassNotFoundException {
        String path = "classes/" + name.replace('.', '/') + ".class";
        try (InputStream is = getClass().getClassLoader().getResourceAsStream(path)) {
            byte[] bytes = IOUtils.toByteArray(is);
            return defineClass(name, bytes, 0, bytes.length);
        } catch (IOException e) {
            throw new ClassNotFoundException(name, e);
        }
    }
}

// G1 GC 相關 JVM 參數
-XX:+UseG1GC                    // 啟用 G1
-XX:MaxGCPauseMillis=200        // 目標停頓時間
-XX:G1HeapRegionSize=16m        // Region 大小 (1MB-32MB)
-XX:InitiatingHeapOccupancyPercent=45  // 觸發Mixed GC既閾值
-XX:G1NewSizePercent=5          // 年輕代最小比例
-XX:G1MaxNewSizePercent=60      // 年輕代最大比例

// Mixed GC 既觸發過程
// 1. 進入 Mixed GC 條件：
//    old region 佔用 > 45% (IHOP)
// 2. 收集計劃：
//    - 收集所有 young region
//    - 收集 n 個 old region (根據停頓時間動態調整)
// 3. 收集策略：
//    - CSet (Collection Set) = 要收集既 Region 集合
//    - 選擇回收價值最高既 Region (存活對象最少)
// 4. 複制過程：
//    - 類似 Copying GC
//    - 將存活對象從 old region 拷貝到 survivor region
//    - 更新引用

// 監控 G1 GC
jstat -gcutil <pid> 1000
// 重點關注：
// - S0/S1/E: Survivor 使用率
// - O: Old 區使用率
// - M: Metaspace 使用率
// - CC: 壓縮次數

// 可以通過 OpenJDK 既 tools.jar 看到內部結構
// 或使用 JOL (Java Object Layout) 庫
<dependency>
    <groupId>org.openjdk.jol</groupId>
    <artifactId>jol-core</artifactId>
    <version>0.17</version>
</dependency>

