// CRC16 計算 key 既 slot
#define CLUSTER_SLOTS 16384

unsigned int CRC16(const char *key, int len) {
    // Redis 既 CRC16 實現
}

unsigned int keyHashSlot(char *key, int keylen) {
    int s = -1;
    char *e;

    // 如果 key 包含 {，只用 { } 既部分計算 hash
    // 呢個係 tag 既機制
    e = strchr(key, '{');
    if (e) {
        key = e + 1;
        e = strchr(key, '}');
        if (e && e > key) keylen = e - key;
    }

    s = CRC16(key, keylen) % CLUSTER_SLOTS;
    return s;
}

