// InnoDB 記錄既隱藏字段
// /storage/innobase/include/dict0mem.h
struct dict_row_t {
    trx_id_t trx_id;      // 最後修改既事務ID
    roll_ptr_t roll_ptr; // 指向 undo log 既指針
};

// Read View 結構
// /storage/innobase/include/read0read.h
class ReadView {
    trx_id_t m_low_limit_id;   // max_trx_id
    trx_id_t m_up_limit_id;   // min_trx_id  
    trx_id_t m_creator_trx_id; // 自己既trx_id
    std::vector<trx_id_t> m_ids; // 活躍事務列表
};

// MVCC 讀取流程
row_search_for_mysql() {
    // 1. 獲取 Read View
    ReadView *view = trx_assign_read_view();

    // 2. 遍歷版本鏈
    for (rec = page_get_first(); rec; rec = page_get_next(rec)) {
        trx_id = rec->trx_id;

        // 3. 判斷可見性
        if (trx_id < view->m_up_limit_id) {
            // 可以讀！
            return rec;
        } else if (trx_id >= view->m_low_limit_id) {
            // 喺我之後開始既，唔可以讀
            continue;
        } else if (trx_id_in_array(trx_id, view->m_ids)) {
            // 我自己既未提交，唔可以讀
            continue;
        } else {
            // 可以讀
            return rec;
        }
    }
}

// 例子：
// T1: begin; select (獲得read view, m_ids=[1])
// T2: begin; update set x=2 where id=1; commit
// T1: select -> 睇到既係舊值 x=1 (因為T2既trx_id在m_ids中)

// Next-Key Lock 既實現
// 當執行：
SELECT * FROM users WHERE age = 20 FOR UPDATE;

// InnoDB 既 lock 結構：
struct lock_rec_t {
    space_id;    // 表空間ID
    page_no;     // 頁號
    n_bits;      // bit數 = 頁中記錄數 + 1
};

// Gap Lock 區間：
// 如果 age = 20 既 record lock 係 index=5
// Gap 1: (prev_record, current) = (10, 20)
// Gap 2: (current, next_record) = (20, 30)

// 實際加既 lock：
// LOCK_ORDINARY (Next-Key Lock):
//   lock on page#N, bits [5, 6] -> 鎖住 20 呢條記錄 + (20, 30) 既gap
// LOCK_GAP:
//   lock on page#N, bit 5 -> 只鎖住 (10, 20) 既gap

// 例子：
// T1: SELECT * FROM users WHERE age = 20 FOR UPDATE;
// T2: INSERT INTO users (age) VALUES (15);  // 會被 gap lock 阻塞！
// T2: INSERT INTO users (age) VALUES (25);  // 會被 next-key lock 阻塞！

// 但注意：
// SELECT * FROM users WHERE age > 20;
// 呢個會使用 Gap Lock 鎖住 (20, +∞)
//
// INSERT INTO users (age) VALUES (100);
// 會被阻塞，因為要插入既位置被 lock 住

